// Time:  O(n)
// Space: O(26)

// greedy, hash table
class Solution {
public:
    int maxSubstrings(string word) {
        static const int L = 4;

        int result = 0;
        unordered_map<char, int> lookup;
        for (int i = 0; i < size(word); ++i) {
            if (!lookup.count(word[i])) {
                lookup[word[i]] = i;
            } else if (i - lookup[word[i]] + 1 >= L) {
                ++result;
                lookup.clear();
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(26)

# greedy, hash table
class Solution(object):
    def maxSubstrings(self, word):
        """
        :type word: str
        :rtype: int
        """
        L = 4
        result = 0
        lookup = {}
        for i, c in enumerate(word):
            if c not in lookup:
                lookup[c] = i
            elif i-lookup[c]+1 >= L:
                result += 1
                lookup.clear()
        return result
